import{_ as a,a as r,b as s,c as o}from"./chunks/fizz.C1J5EiKo.js";import{_ as n,C as i,o as d,c as l,E as p,a2 as c}from"./chunks/framework.CkaEw-3u.js";const g="/mug-typography-docs/image/loop.webp",C=JSON.parse('{"title":"変形（デフォーム）させる","description":"5種類の組み込み変形エフェクトと対象指定の使い方","frontmatter":{"title":"変形（デフォーム）させる","description":"5種類の組み込み変形エフェクトと対象指定の使い方","pageClass":"feature-guide","aside":false},"headers":[],"relativePath":"features/feature-deform.md","filePath":"features/feature-deform.md"}'),h={name:"features/feature-deform.md"};function m(u,t,f,_,b,P){const e=i("FeatureHero");return d(),l("div",null,[p(e,{eyebrow:"MOTION & DEFORMATION",title:"輪郭そのものが動きはじめる",description:"パルス、台形、球面、樽型、手描き風。文字のアウトラインへ直接働く5種類の変形を重ね、有機的なモーションを生み出せます。",image:"/image/loop.webp","image-alt":"輪郭が揺らぐ手描き風デフォームアニメーション","detail-link":"/reference/reference-animation-settings#パス変形エフェクト-path-deformation-effects","point-one":"5種類の組み込み効果","point-two":"文字ごとの位相制御","point-three":"対象パーツを限定"}),t[0]||(t[0]=c('<h2 id="エフェクトを選ぶ" tabindex="-1">エフェクトを選ぶ <a class="header-anchor" href="#エフェクトを選ぶ" aria-label="Permalink to &quot;エフェクトを選ぶ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>エフェクト</th><th>動き</th><th>サンプル</th></tr></thead><tbody><tr><td><strong>Pulse</strong></td><td>輪郭を内外へ膨張・収縮</td><td><img src="'+a+'" alt="Pulse"></td></tr><tr><td><strong>Trapezoid</strong></td><td>指定した軸に沿って台形状に変形</td><td><img src="'+r+'" alt="Trapezoid"></td></tr><tr><td><strong>Sphere</strong></td><td>球面のように中央を膨張・収縮</td><td><img src="'+s+'" alt="Sphere"></td></tr><tr><td><strong>Barrel</strong></td><td>樽型・糸巻き型に歪ませる</td><td><img src="'+o+'" alt="Barrel"></td></tr><tr><td><strong>Hand Drawn</strong></td><td>輪郭の揺れと姿勢のジッターを合成</td><td><img src="'+g+`" alt="Hand Drawn"></td></tr></tbody></table><h2 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h2><ol><li><strong>Page</strong> を <code>Animation Settings</code> にします。</li><li>使いたいエフェクトのグループを開き、<strong>Enabled</strong> をオンにします。</li><li><strong>Amplitude</strong>（Hand Drawn では Wobble / Jitter）で変形量を決めます。</li><li><strong>Speed (Hz)</strong> と <strong>Phase</strong> で動く速さと開始位置を整えます。</li><li>必要なら <strong>Targets</strong> で適用先を限定します。</li></ol><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>デフォームは複数同時に適用できます、弱い効果を重ねると複雑な動きを作れます。</p></div><h2 id="文字ごとに波をずらす" tabindex="-1">文字ごとに波をずらす <a class="header-anchor" href="#文字ごとに波をずらす" aria-label="Permalink to &quot;文字ごとに波をずらす&quot;">​</a></h2><p><strong>Char Phase</strong> は文字ごとの波の位相を、<strong>Char Delay</strong> は文字ごとの開始時刻をずらします。連続した文字へ順番に動きを伝えるなら Char Phase、時間差ではっきり始動させるなら Char Delay が向いています。</p><p><strong>Step</strong> を上げると動きを連続値から段階的な変化へ近づけられます。</p><h2 id="targets-で一部だけ変形する" tabindex="-1">Targets で一部だけ変形する <a class="header-anchor" href="#targets-で一部だけ変形する" aria-label="Permalink to &quot;Targets で一部だけ変形する&quot;">​</a></h2><p>Targets が空欄なら、エフェクトはすべてのパーツに適用されます。文字は <code>c</code>、パーツは <code>p</code> に1始まりの番号を続けて指定します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>c1-c3       # 1〜3文字目</span></span>
<span class="line"><span>p2 p5       # 2番目と5番目のパーツ</span></span>
<span class="line"><span>!c1         # 1文字目以外</span></span></code></pre></div><p>番号は Character Settings / Part Settings の並びと対応します。詳しい文法は <a href="/mug-typography-docs/reference/reference-output-settings.html#targets-対象指定-の記述フォーマット">Targets の記述フォーマット</a> を参照してください。</p><h2 id="手描き風を静止させる" tabindex="-1">手描き風を静止させる <a class="header-anchor" href="#手描き風を静止させる" aria-label="Permalink to &quot;手描き風を静止させる&quot;">​</a></h2><p>Hand Drawn の <strong>Pattern Count</strong> を <code>1</code> にすると、揺れのパターンを固定できます。静止画として手描き感が欲しいときに便利です。</p>`,14))])}const x=n(h,[["render",m]]);export{C as __pageData,x as default};
